<?php namespace App\Http\Controllers\Api\Admin; use App\Http\Controllers\Controller; use App\Models\Brand; use Illuminate\Http\Request; class AdminBrandController extends Controller { public function index() { return Brand::all(); } public function store(Request $request) { return Brand::create($request->all()); } public function update(Request $request, Brand $brand) { $brand->update($request->all()); return $brand; } public function destroy(Brand $brand) { $brand->delete(); return response()->noContent(); } }